  ('elementary-6f0ba476-moex-00920', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依據我國加值及非加值型營業稅法之規定，下列有關營業稅銷售額之敘述何者錯誤？', '["營業人銷售貨物或勞務所收取之全部代價，應包括營業人在貨物或勞務之價額外收取之一切費用", "營業稅法第14條所稱之銷售額應包含當次銷售之營業稅額", "空運事業中的客運，其銷售額是指自中華民國境內承載旅客至中華民國境外第一站間之票價", "應徵貨物稅、菸酒稅或菸品健康福利捐之貨物，其銷售額應加計貨物稅額、菸酒稅額或菸品健康福利 捐金額在內"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
