  ('elementary-6f0ba476-moex-00922', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '住在臺灣的小明是中華民國國民，熱衷網路購物，若小明在感恩節透過美國電商亞馬遜網站直接購入咖 啡機一部價值2萬元，並選擇直接寄送到臺灣，試問該貨物之進口營業稅應由誰繳納？', '["由境外電商繳納", "由收貨人小明繳納", "在境外購買貨物進口無須繳納我國的營業稅", "由境外電商委託臺灣的代理人繳納"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
